struct LyricView: View {
    @ObservedObject var viewModel: PlayerViewModel
    @State var isAnimating = false

    var body: some View {
        ScrollView {
            LazyVStack {
                ForEach(viewModel.lyrics.indices, id: \.self) { index in
                    let lyric = viewModel.lyrics[index]
                    Text(lyric.text)
                        .font(viewModel.currentIndex == index ? .title : .body)
                        .scaleEffect(viewModel.currentIndex == index ? 1.2 : 1.0)
                        .animation(.spring(), value: viewModel.currentIndex)
                        .onTapGesture {
                            viewModel.seek(to: lyric.timestamp)
                        }
                }
            }
        }
        .onAppear {
            isAnimating = true
        }
    }
}
